+        const message = JSON.parse(event.data) as {
+          type?: unknown;
+          channel?: unknown;
+          message?: { id?: unknown; type?: unknown; payload?: unknown };
+          ackRequired?: unknown;
+          code?: unknown;
+        };
+
+        if (message.type === "subscribed") {
+          setConnected(true);
+          return;
+        }
+
+        if (message.type === "error") {
+          // Subscription errors (e.g. auth) mean real-time updates are not active.
+          if (
